def heuristic_fills_without_trades_alert(strategy_name: str, stats: dict, fill_info: dict) -> tuple:
    """Detect strategies with filled orders but zero attributed closed trades (signals broken COID attribution)."""
    placed = fill_info.get("placed", 0)
    trades_lifetime = stats.get("trades_lifetime", 0)
    if placed >= 5 and trades_lifetime == 0:
        return True, (
            f"ATTRIBUTION_BROKEN: strategy '{strategy_name}' has {placed} fills "
            f"but 0 attributed closed trades. "
            f"Check analyzer._strategy_from_client_id includes '{strategy_name}' prefix."
        )
    return False, ""

new_heuristic_proposals.test_addition:
class TestFillsWithoutTradesAlert(unittest.TestCase):
    def test_triggers_on_many_fills_zero_trades(self):
        fired, reason = heuristic_fills_without_trades_alert(
            'crypto-oversold-bounce', {'trades_lifetime': 0}, {'placed': 16}
        )
        self.assertTrue(fired)
        self.assertIn('ATTRIBUTION_BROKEN', reason)
        self.assertIn('crypto-oversold-bounce', reason)

    def test_no_trigger_below_threshold(self):
        fired, _ = heuristic_fills_without_trades_alert(
            'crypto-momentum', {'trades_lifetime': 0}, {'placed': 3}
        )
        self.assertFalse(fired)

    def test_no_trigger_when_trades_exist(self):
        fired, _ = heuristic_fills_without_trades_alert(
            'geo-defense', {'trades_lifetime': 2}, {'placed': 10}
        )
        self.assertFalse(fired)

    def test_no_trigger_on_missing_fill_info(self):
        fired, _ = heuristic_fills_without_trades_alert(
            'crypto-oversold-bounce', {'trades_lifetime': 0}, {}
        )
        self.assertFalse(fired)
